action.command:
sed -n '1,260p' train.py && printf '\n--- model.py ---\n' && sed -n '1,260p' model.py && printf '\n--- predict.py ---\n' && sed -n '1,320p' predict.py && printf '\n--- metrics summaries ---\n' && python - <<'PY'
import json, os, glob, torch
for p in sorted(glob.glob('logs/iter_*/metrics.jsonl')):
    vals=[]
    try:
        with open(p) as f:
            for line in f:
                if line.strip(): vals.append(json.loads(line))
    except Exception as e:
        print(p, 'ERR', e); continue
    if vals:
        print(p, 'n=', len(vals), 'first=', vals[0], 'last=', vals[-1])
        if len(vals)>5: print('  last5=', vals[-5:])
for ck in sorted(glob.glob('checkpoints/*.pt')):
    try:
        d=torch.load(ck, map_location='cpu')
        print('CKPT', ck, {k:d.get(k) for k in ['epoch','args'] if k in d})
    except Exception as e:
        print('CKPT', ck, 'ERR', e)
PY
